import{_ as t,o,c as r,a2 as d}from"./chunks/framework.il0noOp3.js";const h=JSON.parse('{"title":"Azure Scout — Master Design & Plan","description":"Master design and delivery plan for Azure Scout — the single source of truth for architecture, work items, audit findings, and roadmap.","frontmatter":{"description":"Master design and delivery plan for Azure Scout — the single source of truth for architecture, work items, audit findings, and roadmap."},"headers":[],"relativePath":"design/master-plan.md","filePath":"design/master-plan.md"}'),a={name:"design/master-plan.md"};function n(s,e,i,c,l,u){return o(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="azure-scout-—-master-design-plan" tabindex="-1">Azure Scout — Master Design &amp; Plan <a class="header-anchor" href="#azure-scout-—-master-design-plan" aria-label="Permalink to &quot;Azure Scout — Master Design &amp; Plan&quot;">​</a></h1><blockquote><p><strong>Status:</strong> Living document. This is the single consolidated source of truth for the Azure Scout evolution: architecture, all work items, audit findings and their fixes, new feature requests, and the release plan. When something is found, decided, or shipped, it is recorded here and reflected in ADO.</p></blockquote><ul><li><strong>ADO project:</strong> <code>This Is My Demo — Azure Scout</code> (dev.azure.com/hybridcloudsolutions)</li><li><strong>GitHub repo:</strong> <code>thisismydemo/azure-scout</code></li><li><strong>Working branch:</strong> <code>claude/repo-access-wexuku</code></li><li><strong>Governance:</strong> HCS split source-of-truth — ADO masters Epic→Feature→Story→Task; GitHub masters Bug/Feature-request intake.</li><li><strong>Last updated:</strong> 2026-07-23 (runtime + live-tenant verification complete; §8 corrected)</li></ul><h3 id="companion-documents-source-of-record" tabindex="-1">Companion documents (source of record) <a class="header-anchor" href="#companion-documents-source-of-record" aria-label="Permalink to &quot;Companion documents (source of record)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Document</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="./enhancement-spec.html"><code>enhancement-spec.md</code></a></td><td><strong>The owner&#39;s original AzureScout Enhancement Specification, verbatim</strong> — the source requirement this whole plan derives from (§0–§12: architecture, engine, ingest, benchmark, reporting, build phases).</td></tr><tr><td><a href="./task-list.html"><code>task-list.md</code></a></td><td>Complete flat list of every task (161 ADO items / 91 GitHub issues) grouped by release/epic.</td></tr><tr><td><a href="./assessment-registry.html"><code>assessment-registry.md</code></a></td><td>Catalogue of every runnable assessment (category, sub-bundles, CAF/WAF coverage, tags).</td></tr><tr><td><a href="./../roadmap.html"><code>../roadmap.md</code></a> · <a href="https://github.com/thisismydemo/azure-scout/blob/main/RELEASES.md" target="_blank" rel="noreferrer"><code>RELEASES.md</code></a></td><td>Public roadmap and release/build ledger.</td></tr></tbody></table><h3 id="⚠️-ado-verification-status-2026-07-21-07-20-utc" tabindex="-1">⚠️ ADO verification status (2026-07-21 07:20 UTC) <a class="header-anchor" href="#⚠️-ado-verification-status-2026-07-21-07-20-utc" aria-label="Permalink to &quot;⚠️ ADO verification status (2026-07-21 07:20 UTC)&quot;">​</a></h3><p>The ADO work-item state described in §4–§6 was authored during the earlier session (commits 00:02–00:26 UTC). <strong>It has NOT been re-verified against the live ADO board in the current session</strong> — every ADO MCP call this session was blocked at the approval/permission step. Treat the AB# numbers below as the <em>intended</em> board state until a live ADO query confirms them. <strong>Open action: verify the board (see §8.6).</strong></p><hr><h2 id="_1-vision" tabindex="-1">1. Vision <a class="header-anchor" href="#_1-vision" aria-label="Permalink to &quot;1. Vision&quot;">​</a></h2><p>Extend Azure Scout from an inventory tool into a <strong>read-only CAF/WAF landing-zone assessment platform</strong> with a modern, tiered reporting engine — and make CAF/WAF analytics available <strong>per discovery domain</strong>, not just as a whole-tenant roll-up.</p><h2 id="_2-architecture-—-three-layers-json-on-disk" tabindex="-1">2. Architecture — three layers, JSON on disk <a class="header-anchor" href="#_2-architecture-—-three-layers-json-on-disk" aria-label="Permalink to &quot;2. Architecture — three layers, JSON on disk&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>COLLECT  --collect.json--&gt;  ASSESS  --findings.json--&gt;  REPORT</span></span>\n<span class="line"><span>(extend, exists)            (new)                       (rebuild)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>The JSON-on-disk contract lets each layer run independently: collect once and assess later, or re-render reports from an existing findings set without re-scanning. <strong>Read-only throughout</strong> (Reader at MG root + read-only Graph).</p><p>Repository layout (implemented on the working branch): <code>src/Invoke-AzureScout.ps1</code>, <code>manifests/assessments.psd1</code>, <code>src/assess/</code> (engine + rules + benchmarks), <code>src/ingest/</code>, <code>src/report/</code> (+ renderers + templates), <code>.ado/azure-pipelines.yml</code>. See <a href="https://github.com/thisismydemo/azure-scout/blob/main/src/README.md" target="_blank" rel="noreferrer"><code>src/README.md</code></a>.</p><h2 id="_3-scope-model-—-how-scout-collects" tabindex="-1">3. Scope model — how Scout collects <a class="header-anchor" href="#_3-scope-model-—-how-scout-collects" aria-label="Permalink to &quot;3. Scope model — how Scout collects&quot;">​</a></h2><ul><li><strong>Default = tenant-wide</strong>: <code>Get-AzSubscription -TenantId</code> returns every accessible subscription.</li><li><strong>&quot;Root MG down = everything&quot;</strong> holds <strong>when the identity has Reader at the tenant-root management group</strong> (inheritance is what delivers full coverage). Collection is access-driven at the subscription plane; the MG hierarchy is captured as inventory and used as a <em>filter</em>, not a tree-walk.</li><li><code>-ManagementGroup</code> narrows to a subtree; <code>-SubscriptionID</code> narrows to specific subs; <code>-Category</code> narrows to a resource domain.</li></ul><hr><h2 id="_4-current-state-verified" tabindex="-1">4. Current state (verified) <a class="header-anchor" href="#_4-current-state-verified" aria-label="Permalink to &quot;4. Current state (verified)&quot;">​</a></h2><ul><li><strong>ADO ↔ GitHub reconciled</strong>: 91 ADO items (#315–#405) ↔ 91 GitHub issues (#1–#161), 1:1 linked. GitHub issues carry <code>ado-tracked</code> + ADO-link comment; ADO items carry a Hyperlink to their GitHub issue and are parented to Epic #5023.</li><li><strong>Standards applied</strong>: detailed descriptions (what/why/in-scope/out-of-scope), acceptance criteria, area paths (Collect/Assess/Ingest/Benchmark/Report/Platform), iterations (<code>2026-Q3-S1..S6</code>), vocabulary tags.</li><li><strong>Code scaffolded</strong> on the working branch (commit history): full three-layer tree + CAF/WAF rule files + tiered reporting + docs.</li></ul><hr><h2 id="_5-work-item-index" tabindex="-1">5. Work-item index <a class="header-anchor" href="#_5-work-item-index" aria-label="Permalink to &quot;5. Work-item index&quot;">​</a></h2><h3 id="epic-ab-5023-—-caf-waf-landing-zone-assessment-platform" tabindex="-1">Epic AB#5023 — CAF/WAF landing-zone assessment platform <a class="header-anchor" href="#epic-ab-5023-—-caf-waf-landing-zone-assessment-platform" aria-label="Permalink to &quot;Epic AB#5023 — CAF/WAF landing-zone assessment platform&quot;">​</a></h3><p>9 new Features + 23 stories, plus 79 reconciled existing Features/Stories/Bugs.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Area</th><th>Focus</th></tr></thead><tbody><tr><td>AB#5024</td><td>Platform</td><td>Module registry + <code>Invoke-AzureScout</code> entry point</td></tr><tr><td>AB#5027</td><td>Assess</td><td>Declarative rule engine (JSONPath, evaluator, loader)</td></tr><tr><td>AB#5031</td><td>Assess</td><td>CAF 8-area + WAF 5-pillar rule files</td></tr><tr><td>AB#5034</td><td>Assess</td><td>Assessment runner + dual CAF/WAF scoring</td></tr><tr><td>AB#5037</td><td>Ingest</td><td>AzGovViz + ARG query pack + Advisor → <code>collect.json</code></td></tr><tr><td>AB#5041</td><td>Benchmark</td><td>ALZ benchmark diff</td></tr><tr><td>AB#5044</td><td>Report</td><td>Tiered renderer engine (PowerBi/Html/Pptx/Excel/Json)</td></tr><tr><td>AB#5050</td><td>Platform</td><td>Permission pre-flight + unattended pipeline</td></tr><tr><td>AB#5053</td><td>Report</td><td>React report variant + cross-run drift tracking</td></tr></tbody></table><h3 id="epic-ab-5056-—-per-domain-caf-waf-analytics-across-all-categories" tabindex="-1">Epic AB#5056 — Per-domain CAF/WAF analytics across all categories <a class="header-anchor" href="#epic-ab-5056-—-per-domain-caf-waf-analytics-across-all-categories" aria-label="Permalink to &quot;Epic AB#5056 — Per-domain CAF/WAF analytics across all categories&quot;">​</a></h3><p>Foundation + one Feature per Scout category (independently runnable, categorized, tagged).</p><table tabindex="0"><thead><tr><th>Feature</th><th>Scope</th></tr></thead><tbody><tr><td>AB#5057 (+ stories #5058–#5060)</td><td>Taxonomy: manifest <code>Category</code>/<code>Frameworks</code>/<code>Tags</code>, <code>-Assessment &lt;Category&gt;</code> scoped run, assessment registry doc</td></tr><tr><td>AB#5061</td><td>Management (sub-bundles: Governance, Policy, UpdateManager, Backup, Automation)</td></tr><tr><td>AB#5062</td><td>Monitor (Monitoring, Alerting, Diagnostics)</td></tr><tr><td>AB#5063</td><td>Networking (Connectivity, Firewall, PrivateLink)</td></tr><tr><td>AB#5064</td><td>Identity (PIM, ConditionalAccess, RBAC)</td></tr><tr><td>AB#5065</td><td>Security (Defender, KeyVault, SecureScore)</td></tr><tr><td>AB#5066</td><td>Compute (Resiliency, CostCleanup)</td></tr><tr><td>AB#5067</td><td>Storage (DataProtection, Redundancy)</td></tr><tr><td>AB#5068</td><td>Databases (Resiliency, DataProtection)</td></tr><tr><td>AB#5069</td><td>Containers (AKS, Registry)</td></tr><tr><td>AB#5070</td><td>Web (AppService, Functions)</td></tr><tr><td>AB#5071</td><td>Analytics (Purview, DataPlatform)</td></tr><tr><td>AB#5072</td><td>AI (ResponsibleAI, PrivateAI)</td></tr><tr><td>AB#5073</td><td>Integration (Messaging, APIM)</td></tr><tr><td>AB#5074</td><td>Hybrid (Arc, AzureLocal)</td></tr><tr><td>AB#5075</td><td>IoT (IoTHub, DPS)</td></tr></tbody></table><h3 id="reconciled-existing-features-from-github-—-ab-315–-405" tabindex="-1">Reconciled existing Features (from GitHub) — AB#315–#405 <a class="header-anchor" href="#reconciled-existing-features-from-github-—-ab-315–-405" aria-label="Permalink to &quot;Reconciled existing Features (from GitHub) — AB#315–#405&quot;">​</a></h3><p>Collectors, runtime/auth/pipeline, and the reporting/diagram features. Full list in ADO under Epic #5023. Mapped to code files on the working branch.</p><hr><h2 id="_6-audit-findings-recommendations" tabindex="-1">6. Audit findings &amp; recommendations <a class="header-anchor" href="#_6-audit-findings-recommendations" aria-label="Permalink to &quot;6. Audit findings &amp; recommendations&quot;">​</a></h2><p>Cross-layer correctness audit (2026-07-20). <strong>All findings are now logged as authored ADO Bugs (AB#5076–#5092), each parented to the Feature that owns the fix and tagged <code>audit</code>.</strong> Severity: 🔴 wrong/lost data · 🟠 robustness · 🟡 polish.</p><table tabindex="0"><thead><tr><th>Bug</th><th>Finding</th><th>Parent Feature</th></tr></thead><tbody><tr><td>AB#5076</td><td>MG query unpaged (drops subs &gt;1000)</td><td>AB#353</td></tr><tr><td>AB#5077</td><td>Bare <code>Exit</code> kills host/runbook</td><td>AB#353</td></tr><tr><td>AB#5078</td><td>&gt;200-sub batch off-by-one / double-count</td><td>AB#354</td></tr><tr><td>AB#5079</td><td>One bad sub aborts whole tenant run</td><td>AB#397</td></tr><tr><td>AB#5080</td><td>No zero-resources guard</td><td>AB#401</td></tr><tr><td>AB#5081</td><td><code>Invoke-Collect</code> adapter missing</td><td>AB#5024</td></tr><tr><td>AB#5082</td><td>Discovery↔assessment data-shape mismatch</td><td>AB#5024</td></tr><tr><td>AB#5083</td><td>JSONPath <code>.length</code> + exception-as-Pass</td><td>AB#5027</td></tr><tr><td>AB#5084</td><td>Benchmark silent all-Fail w/o governance</td><td>AB#5041</td></tr><tr><td>AB#5085</td><td><code>percentageAtLeast</code> zero-denom / value:0</td><td>AB#5027</td></tr><tr><td>AB#5086</td><td>WAF-RE-05 no &quot;where supported&quot;</td><td>AB#5031</td></tr><tr><td>AB#5087</td><td><code>AreaWeight</code> dead / unweighted framework score</td><td>AB#5034</td></tr><tr><td>AB#5088</td><td><code>Unknown</code> rules silently dropped</td><td>AB#5034</td></tr><tr><td>AB#5089</td><td>Null severity sorts to top / PPTX crash</td><td>AB#5034</td></tr><tr><td>AB#5090</td><td>HTML null area score renders red</td><td>AB#5044</td></tr><tr><td>AB#5091</td><td>Banker&#39;s rounding / Excel sheet collision</td><td>AB#5044</td></tr><tr><td>AB#5092</td><td>Power BI join needs stable <code>AreaKey</code></td><td>AB#5044</td></tr></tbody></table><h3 id="discovery-collection-modules" tabindex="-1">Discovery / collection (<code>Modules/</code>) <a class="header-anchor" href="#discovery-collection-modules" aria-label="Permalink to &quot;Discovery / collection (`Modules/`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Sev</th><th>Location</th><th>Finding</th><th>Fix</th><th>Track under</th></tr></thead><tbody><tr><td>🔴</td><td><code>Get-AZTIManagementGroups.ps1:25</code></td><td><code>Search-AzGraph -First 1000</code> unpaged — drops subs past 1000 in large MGs</td><td>Add <code>SkipToken</code> paging loop</td><td>new Bug → AB#354/#353 area</td></tr><tr><td>🔴</td><td><code>Get-AZTIManagementGroups.ps1:34</code>, <code>Start-AZTIGraphExtraction.ps1:61</code></td><td>Bare <code>Exit</code> kills host/runbook, uncatchable</td><td><code>throw</code> instead</td><td>new Bug</td></tr><tr><td>🔴</td><td><code>Invoke-AZTIInventoryLoop.ps1:41-82</code></td><td>Off-by-one inclusive range → subs double-queried/double-counted</td><td><code>..($NEnd-1)</code> + clamp</td><td>new Bug</td></tr><tr><td>🟠</td><td><code>Invoke-AZTIInventoryLoop.ps1:50-96</code></td><td>Fallback query unwrapped — one bad sub aborts whole tenant</td><td>try/catch + continue</td><td>new Bug</td></tr><tr><td>🟠</td><td>orchestrator</td><td>No &quot;0 resources extracted&quot; guard</td><td>add top-level warning</td><td>AB#401 (empty-data guard)</td></tr><tr><td>🟡</td><td><code>AllSubscriptions.ps1:61</code></td><td>MG-path enrichment capped at 1000 (cosmetic)</td><td>page or flag</td><td>new Bug</td></tr></tbody></table><p><strong>Correct as-is:</strong> main inventory loop pages correctly; default = all accessible subs; MG hierarchy captured top-down; permission model matches &quot;Reader @ root MG → everything&quot;.</p><h3 id="assessment-src-assess" tabindex="-1">Assessment (<code>src/assess/</code>) <a class="header-anchor" href="#assessment-src-assess" aria-label="Permalink to &quot;Assessment (`src/assess/`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Sev</th><th>Location</th><th>Finding</th><th>Fix</th><th>Track under</th></tr></thead><tbody><tr><td>🔴</td><td><code>Invoke-AzureScout.ps1:63</code></td><td><code>Invoke-Collect</code> (flat→nested adapter) does not exist — assessment can&#39;t run end-to-end</td><td>Build the adapter, or rewrite rule queries against the flat collector schema</td><td>AB#5024</td></tr><tr><td>🔴</td><td>rules vs <code>Modules/**</code> output</td><td><strong>Data-shape mismatch</strong>: rules assume nested ARM tree (<code>$.networking.virtualNetworks[*].properties…</code>); collectors emit flat Excel-row objects → every query returns 0 → false Fail / vacuous Pass</td><td>Adapter or rule rewrite (same as above)</td><td>AB#5024/#5031</td></tr><tr><td>🔴</td><td><code>caf.network.yaml:8</code>, <code>waf.reliability.yaml:8</code></td><td>Newtonsoft JSONPath doesn&#39;t support <code>.length</code> in filters; exception swallowed → for <code>countEquals 0</code> reads as false <strong>Pass</strong></td><td>Precompute scalar counts in adapter; make <code>Resolve-JsonPath</code> distinguish &quot;threw&quot; from &quot;0 matches&quot;</td><td>AB#5027/#5031</td></tr><tr><td>🔴</td><td><code>Compare-Benchmark.ps1</code></td><td>Silently all-Fail when <code>$Collect.governance</code> unset (AzGovViz not run)</td><td>Guard: return Unknown/skip when governance absent</td><td>AB#5041</td></tr><tr><td>🟡</td><td><code>Invoke-Rule.ps1:42</code></td><td><code>percentageAtLeast</code> zero-denominator → Fail instead of Unknown; <code>value:0</code> always passes</td><td>Treat 0-denom as Unknown</td><td>AB#5027</td></tr><tr><td>🟡</td><td><code>waf.reliability.yaml</code> WAF-RE-05</td><td>Zone rule has no &quot;where supported&quot; qualifier → false negatives</td><td>Scope to zone-eligible SKUs</td><td>AB#5031</td></tr></tbody></table><h3 id="analytics-scoring-reporting-get-score-ps1-src-report" tabindex="-1">Analytics / scoring &amp; reporting (<code>Get-Score.ps1</code>, <code>src/report/</code>) <a class="header-anchor" href="#analytics-scoring-reporting-get-score-ps1-src-report" aria-label="Permalink to &quot;Analytics / scoring &amp; reporting (`Get-Score.ps1`, `src/report/`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Sev</th><th>Location</th><th>Finding</th><th>Fix</th><th>Track under</th></tr></thead><tbody><tr><td>🔴</td><td><code>Get-Score.ps1:32-37</code></td><td><code>AreaWeight</code> is dead data; framework score is unweighted mean of area scores</td><td>Weight by rule count or <code>AreaWeight</code>, or remove the field</td><td>AB#5034</td></tr><tr><td>🔴</td><td><code>Get-Score.ps1:18</code> / <code>Invoke-Rule.ps1:47</code></td><td><code>Unknown</code>-status rules silently dropped from denominator — broken rule <em>raises</em> score with no signal</td><td>Surface <code>Unknown</code> or fail loudly</td><td>AB#5034</td></tr><tr><td>🔴</td><td><code>Get-Score.ps1:40-43</code>, <code>build_deck.py:46</code></td><td>Null/unknown severity sorts to <strong>top</strong> of exec gap list and crashes PPTX on <code>.upper()</code></td><td><code>$sevRank[...] ?? 99</code>; defensive <code>.get()</code></td><td>AB#5034/#5048</td></tr><tr><td>🟠</td><td><code>report.html.template:34</code></td><td>Null area score renders <strong>red</strong> (<code>null&gt;=50</code> false) though text shows &quot;—&quot;</td><td>Null-check the class expression</td><td>AB#5047</td></tr><tr><td>🟡</td><td><code>Get-Score.ps1:24,35</code></td><td>Banker&#39;s rounding at report thresholds</td><td><code>MidpointRounding::AwayFromZero</code></td><td>AB#5036</td></tr><tr><td>🟡</td><td><code>Export-Excel.ps1:18</code></td><td>31-char sheet-name truncation can merge two areas&#39; evidence</td><td>disambiguate on collision</td><td>AB#5049</td></tr><tr><td>🟡</td><td><code>Export-PowerBi.ps1</code></td><td>Star-schema join by raw <code>(Framework,Area)</code> text — fragile</td><td>emit normalized <code>AreaKey</code></td><td>AB#5046</td></tr></tbody></table><hr><h2 id="_7-new-feature-requests-decisions-captured-here" tabindex="-1">7. New feature requests / decisions captured here <a class="header-anchor" href="#_7-new-feature-requests-decisions-captured-here" aria-label="Permalink to &quot;7. New feature requests / decisions captured here&quot;">​</a></h2><ul><li><strong>Per-domain CAF/WAF analytics</strong> (Epic AB#5056) — every category an independently runnable, tagged assessment. <strong>Added.</strong></li><li><strong>Release/build ledger</strong> — <a href="https://github.com/thisismydemo/azure-scout/blob/main/RELEASES.md" target="_blank" rel="noreferrer"><code>RELEASES.md</code></a>. <strong>Added.</strong></li><li><code>azure-scout</code> retained as a de-facto repo tag (not in the formal vocabulary) — pending decision to keep or strip.</li><li>GitHub roadmap projection (Flow 2) for approved Features — <strong>not done</strong> (bot-only per standard); pending &quot;approve + project&quot; decision.</li></ul><h2 id="_8-open-actions-next" tabindex="-1">8. Open actions (next) <a class="header-anchor" href="#_8-open-actions-next" aria-label="Permalink to &quot;8. Open actions (next)&quot;">​</a></h2><ol><li>✅ <strong>Log the §6 audit findings as ADO Bugs</strong> — done: AB#5076–#5092, parented to their Features.</li><li>✅ <strong>Unblock assessment</strong> (AB#5081, AB#5082, AB#5083) — <code>src/collect/Invoke-Collect.ps1</code> normalized ARG adapter added; <code>.length</code> filters rewritten to scalar fields; <code>Resolve-JsonPath</code>/<code>Invoke-Rule</code> surface thrown queries as <code>Error</code>. <em>Committed, static-validated, not yet runtime-verified.</em></li><li>✅ <strong>Discovery data-loss fixes</strong> (AB#5076, AB#5077, AB#5078) — SkipToken paging, <code>Exit</code>→<code>throw</code>, batch off-by-one. <em>Committed, static-validated.</em></li><li>✅ <strong>Scoring/reporting holes</strong> (AB#5084, AB#5085, AB#5087, AB#5088, AB#5089, AB#5090) — weighted framework score, Unknown/Error surfaced, deterministic rounding, severity-null sort, HTML null-neutral, benchmark governance guard, PPTX severity guard. <em>Committed, static-validated.</em></li><li>✅ <strong>Wire the module manifest</strong> (AB#5024) — <code>Invoke-ScoutAssessment</code>/<code>Test-ScoutPermission</code> exported; <code>src/</code> dot-sourced. <em>Committed <code>ddebe27</code>.</em></li><li>✅ <strong>Per-category rule content</strong> (Epic AB#5056 / AB#5057) — 139 rules across all 23 CAF/WAF files; collector extensions (2026-07-23) flipped 16 more rules from <code>manual</code> to automated (93 automated / 46 manual; every remaining manual rule documents exactly which non-ARG data source it needs).</li><li>✅ <strong>Polish bugs</strong> — AB#5086 (zone scoping), AB#5079/#5080/#5091/#5092 all fixed in code.</li><li>✅ <strong>Runtime verification (2026-07-23)</strong> — first actual execution of the engine, in two stages: <ul><li><strong>Offline</strong>: <code>tests/Assessment.Engine.Tests.ps1</code> 6/6 passing (was 0/6 — four StrictMode defects fixed in <code>Resolve-JsonPath</code>, <code>Get-Score</code>, <code>Invoke-Rule</code>, and an unguarded <code>$spec.Benchmark</code> in <code>Invoke-ScoutAssessment</code> that broke 21 of 22 manifest assessments). Full repo suite 1263 passed / 1 pre-existing unrelated failure (manifest author metadata) / 3 skipped. End-to-end <code>-FromCollect</code> against the new canonical fixture <code>tests/datadump/sample-collect.json</code>: all renderer tiers valid; all 22 manifest entries smoke-tested.</li><li><strong>Live</strong> (HCS tenant, read-only SPN): full <code>collect → assess → report</code> — every ARG query succeeds, 140 findings, all five tiers rendered including the new OpenXML PPTX deck. Live-only bugs found and fixed: <code>Search-AzGraph -Skip 0</code> rejected on first page (both <code>Invoke-Collect</code> and <code>Invoke-ArgQueryPack</code>), <code>mv-expand kind=outer</code> unsupported by ARG, <code>kind</code> reserved-keyword collision, and <code>Import-AzGovViz</code> looping on interactive prompts when run without <code>-ManagementGroupId</code> (now guarded: skips with a warning; benchmark degrades to Unknown per the AB#5084 guard).</li></ul></li><li><strong>Still open:</strong><ul><li>AzGovViz/governance ingest has not run live — requires <code>-ManagementGroupId</code> plus Reader at MG root and read-only Graph app permissions for the SPN.</li><li>Optional: designer-authored <code>deck.pptx.template</code> to replace the programmatic slide master (extension point documented in <code>Export-Pptx.ps1</code> and the §9a decision record).</li><li>ADO board state updates for the items whose acceptance criteria the above verification now satisfies.</li><li>Tag-vocabulary standards PR (Platform Engineering PR #5) awaiting repo-owner approval.</li></ul></li></ol><h3 id="planning-gap-check-2026-07-21" tabindex="-1">Planning gap-check (2026-07-21) <a class="header-anchor" href="#planning-gap-check-2026-07-21" aria-label="Permalink to &quot;Planning gap-check (2026-07-21)&quot;">​</a></h3><p>Full ADO scan: <strong>161 items</strong> (2 Epics, 106 Features, 29 Stories, 24 Bugs) — <strong>0 missing priority, 0 missing acceptance criteria, 0 orphaned items, 0 non-vocabulary tags.</strong> The board is internally consistent.</p><h3 id="delivery-state-2026-07-21" tabindex="-1">Delivery state (2026-07-21) <a class="header-anchor" href="#delivery-state-2026-07-21" aria-label="Permalink to &quot;Delivery state (2026-07-21)&quot;">​</a></h3><p><strong>All 161 items are New (planned/backlog).</strong> ADO reflects planning only — no item is marked delivered, because nothing has been verified.</p><p>Some implementation code exists on branch <code>claude/repo-access-wexuku</code> (the assessment platform scaffold, per-domain rules, and audit fixes), but it is <strong>prototype/unverified</strong> — static-validated only (no pwsh/Az to run it) — and is <strong>not</strong> claimed as done on the board. Work items advance out of New only when their acceptance criteria are actually met and verified.</p><h2 id="_9-build-phases-from-spec-§9" tabindex="-1">9. Build phases (from spec §9) <a class="header-anchor" href="#_9-build-phases-from-spec-§9" aria-label="Permalink to &quot;9. Build phases (from spec §9)&quot;">​</a></h2><p>The owner&#39;s spec defines the build order. Carried in verbatim so the plan follows it.</p><ul><li><strong>Phase 1 — Foundations.</strong> Three-layer JSON contract; <code>-Assessment</code> switch + manifest registry; confirm cost/security modules pull Advisor + Policy compliance (add via ingest if missing). <em>(Maps to AB#5024, AB#5037.)</em></li><li><strong>Phase 2 — Landing Zone module.</strong> Encode CAF 8-area + WAF 5-pillar rule files; rule engine + scoring; governance-visualizer ingest; ARG query pack; ALZ benchmark diff. <em>(AB#5027, AB#5031, AB#5034, AB#5037, AB#5041.)</em></li><li><strong>Phase 3 — Reporting overhaul.</strong> Power BI template + CSV emitters; self-contained HTML; PPTX generator. Demote Excel to evidence tier. <em>(AB#5044 — see §9a reporting decision below.)</em></li><li><strong>Phase 4 — Remaining modules.</strong> Identity (IT/OT boundary rules, directory-source reconciliation inputs); Cost (RI/AHB/orphan/right-size → external TCO feed); app/wave modules scoped as <strong>data feeds to the migration tool, not reimplementations</strong>. <em>(Epic AB#5056 per-domain features.)</em></li><li><strong>Phase 5 — Polish.</strong> React report variant; drift tracking (commit <code>findings.json</code> to Git, diff over runs); one-command pipeline producing all tiers into a dated folder. <em>(AB#5053.)</em></li></ul><h2 id="_9a-reporting-solution-—-design-decision-recorded-no-longer-blocking" tabindex="-1">9a. Reporting solution — design decision (recorded, no longer blocking) <a class="header-anchor" href="#_9a-reporting-solution-—-design-decision-recorded-no-longer-blocking" aria-label="Permalink to &quot;9a. Reporting solution — design decision (recorded, no longer blocking)&quot;">​</a></h2><p>Design Goal #4 requires <strong>replacing Excel-first output with a better, tiered renderer</strong>. Before building AB#5044, a renderer approach needed to be chosen — the spec&#39;s default (python-pptx shell-out for the executive deck) adds a Python dependency and should not be inherited without evaluation.</p><table tabindex="0"><thead><tr><th>Option</th><th>Portable on Linux CI?</th><th>Dependency</th></tr></thead><tbody><tr><td>python-pptx (spec default)</td><td>✅</td><td>python3 + python-pptx</td></tr><tr><td>OpenXML SDK (<code>DocumentFormat.OpenXml</code>)</td><td>✅</td><td>none (pure .NET) — more code</td></tr><tr><td>COM automation</td><td>❌ Windows-only</td><td>PowerPoint installed</td></tr></tbody></table><p><strong>Decision recorded:</strong> <a href="./decisions/pptx-renderer.html"><code>decisions/pptx-renderer.md</code></a> — recommends the <strong>OpenXML SDK</strong> route (pure .NET, no Python runtime, no <code>.ado/azure-pipelines.yml</code> changes needed), templated against a pre-authored <code>deck.pptx.template</code> to keep the &quot;more code&quot; cost bounded. <code>python-pptx</code> and COM automation are both rejected — see the decision record for the full reasoning grounded in this repo&#39;s actual <code>Export-Pptx.ps1</code>/<code>build_deck.py</code> prototype and CI (<code>ubuntu-latest</code>, no <code>pip install</code> step today).</p><p><strong>This is a drafted recommendation, not a unilateral final call.</strong> Picking the reporting library is an architectural decision that needs the repo owner&#39;s sign-off before AB#5044 is built against it. The open ADO action is downgraded from &quot;design the solution&quot; to <strong>&quot;repo owner: confirm or override the recommendation in <code>decisions/pptx-renderer.md</code>&quot;</strong> — no longer a hard blocker on starting AB#5044&#39;s other renderers (Power BI, HTML), since those tiers are unaffected either way. Power BI (primary tier) and self-contained HTML remain unaffected by this decision; it only governs the PPTX deck.</p><h2 id="_10-dependencies-from-spec-§10" tabindex="-1">10. Dependencies (from spec §10) <a class="header-anchor" href="#_10-dependencies-from-spec-§10" aria-label="Permalink to &quot;10. Dependencies (from spec §10)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Requirement</th><th>Why</th></tr></thead><tbody><tr><td>PowerShell</td><td>7.0.3+</td><td>Whole module is PS7; 5.1 unsupported</td></tr><tr><td>Az modules</td><td>Az.Accounts, Az.Resources, Az.ResourceGraph, <strong>Az.Advisor</strong>, <strong>Az.Security</strong></td><td>Auth/tokens, resources/policy, bulk KQL, the one automated WAF signal (Advisor), Defender data</td></tr><tr><td>YAML</td><td>powershell-yaml</td><td>Parses the CAF/WAF rule files — no parser, no rules</td></tr><tr><td>Graph (ingest)</td><td>read-only app perms: User/Group/Application.Read.All, PrivilegedAccess.Read.AzureResources</td><td>AzGovViz ingest reads identity/PIM (read-only)</td></tr><tr><td>PPTX</td><td>.NET SDK (DocumentFormat.OpenXml 3.0.2, auto-acquired via NuGet on first use)</td><td>Executive deck (§9a decision implemented — no Python)</td></tr><tr><td>Power BI</td><td>Power BI Desktop</td><td>Author the <code>.pbit</code> template once; tool emits CSVs</td></tr><tr><td>Diagrams</td><td>draw.io export</td><td>Network topology (already in collection layer)</td></tr></tbody></table><h2 id="_11-scope-discipline-—-what-not-to-build-from-spec-§11" tabindex="-1">11. Scope discipline — what NOT to build (from spec §11) <a class="header-anchor" href="#_11-scope-discipline-—-what-not-to-build-from-spec-§11" aria-label="Permalink to &quot;11. Scope discipline — what NOT to build (from spec §11)&quot;">​</a></h2><ul><li><strong>No remediation / execution.</strong> Assess and report only. Findings carry remediation guidance; <strong>the tool never mutates the tenant.</strong> Read-only throughout (Reader @ MG root + read-only Graph).</li><li><strong>Don&#39;t reimplement the migration/ML tooling.</strong> 6R classification, wave AI, and TCO modeling stay external; this platform <strong>feeds them normalized data</strong>, it does not replace them.</li><li><strong>The architect&#39;s judgment stays human.</strong> Network design intent and CAF gap interpretation are review activities. The tool front-loads evidence and scores what is machine-verifiable; the <strong><code>Manual</code> status</strong> exists precisely to hand the rest to a person with the evidence already attached.</li></ul><h2 id="_12-release-plan" tabindex="-1">12. Release plan <a class="header-anchor" href="#_12-release-plan" aria-label="Permalink to &quot;12. Release plan&quot;">​</a></h2><p>See <a href="https://github.com/thisismydemo/azure-scout/blob/main/RELEASES.md" target="_blank" rel="noreferrer"><code>RELEASES.md</code></a>. Summary: v1.1.0 (quality), v1.2.0 (collector depth), <strong>v2.0.0</strong> (assessment platform — major, breaking output surface), <strong>v2.1.0</strong> (per-domain analytics).</p><hr><h2 id="change-log-for-this-document" tabindex="-1">Change log for this document <a class="header-anchor" href="#change-log-for-this-document" aria-label="Permalink to &quot;Change log for this document&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>2026-07-21</td><td>Initial master plan consolidating architecture, work-item index (Epics #5023 + #5056), the cross-layer audit findings, new feature requests, and the release plan.</td></tr><tr><td>2026-07-21</td><td>Logged all 17 audit findings as ADO Bugs (AB#5076–#5092) parented to their Features; ran full ADO gap-check (0 missing priority/AC/parent/tag issues).</td></tr><tr><td>2026-07-21</td><td>Implemented the critical-path fixes: <code>Invoke-Collect</code> adapter, scalar-field rule rewrites, JSONPath error-surfacing, weighted scoring + Unknown/Error surfacing, reporting null-guards, benchmark governance guard, and the 3 discovery data-loss fixes. Committed and static-validated (no pwsh/Az to runtime-verify).</td></tr><tr><td>2026-07-21</td><td>Added per-domain CAF/WAF analytics prototype (Epic AB#5056): domain ARG collection, 15 category assessments + sub-bundles in the manifest, 10 rule files, registry doc; wired <code>src/</code> into the module as <code>Invoke-ScoutAssessment</code>.</td></tr><tr><td>2026-07-21</td><td>Corrected an overreach: 64 items had been moved to Resolved prematurely — reverted all to New. ADO now reflects planning only; no item is marked delivered until its acceptance criteria are verified.</td></tr><tr><td>2026-07-21</td><td>Carried in the three missing spec sections verbatim — §9 Build phases, §10 Dependencies, §11 Scope discipline — and added §9a: the reporting-solution design decision (evaluate python-pptx vs. OpenXML vs. native before building AB#5044). Renumbered Release plan to §12.</td></tr><tr><td>2026-07-23</td><td>Full backlog implementation pass: collector extensions flipped 16 rules to automated (AB#5057); AB#5044 PPTX renderer rebuilt on DocumentFormat.OpenXml (python-pptx/<code>build_deck.py</code> removed); engine runtime-verified offline (Pester 6/6, fixture end-to-end, all 22 manifest entries) AND live against the HCS tenant (140 findings, all 5 tiers). Fixed 4 StrictMode engine defects + 4 live-only collect/ingest defects (ARG <code>-Skip 0</code>, <code>mv-expand kind=outer</code>, <code>kind</code> keyword, AzGovViz interactive-prompt hang). §8 rewritten to reflect delivered state.</td></tr><tr><td>2026-07-22</td><td>Recorded the §9a reporting-solution decision: <a href="./decisions/pptx-renderer.html"><code>decisions/pptx-renderer.md</code></a> recommends OpenXML SDK over python-pptx/COM, grounded in the current <code>Export-Pptx.ps1</code>/<code>build_deck.py</code> prototype and the <code>ubuntu-latest</code> CI agent. Flagged as a drafted recommendation pending repo owner sign-off — not a unilateral final call. §9a reframed from &quot;open, blocks AB#5044&quot; to &quot;recorded, no longer blocking&quot;.</td></tr></tbody></table>',67)])])}const g=t(a,[["render",n]]);export{h as __pageData,g as default};
